    if (next_off >= a->used) {
        return -1;
    }
    nb.base = oldb->base;
    nb.off = next_off;
    if (z_is_flag(&nb)) {
        return -1;
    }
    ntotal = tag_read_size(&nb);
    if (old_total + ntotal < need) {
        return -1;
    }
    list_remove(a, &nb);
    *merged_out = old_total + ntotal;
    xa0(oldb, *merged_out);
    z_set_flag(oldb, 1);
    return 0;
}
